// Unifica los 3 resultados de IOL en el formato de asset_prices
const acciones = $('IOL — Cotización Acciones (MERVAL)').all();
const cedears  = $('IOL — Cotización CEDEARs').all();
const bonos    = $('IOL — Cotización Bonos').all();

const toRows = (items, type) =>
  items.flatMap(item =>
    (item.json.titulos || []).map(t => ({
      ticker:     t.simbolo,
      price_ars:  t.ultimo,
      price_usd:  null,
      asset_type: type,
      source:     'iol',
      updated_at: new Date().toISOString()
    }))
  );

return [
  ...toRows(acciones, 'accion'),
  ...toRows(cedears,  'cedear'),
  ...toRows(bonos,    'bono'),
].map(row => ({ json: row }));

// FCI usa el nombre del fondo como ticker
const items = $input.all();
return items.map(item => ({
  json: {
    ticker:     item.json.fondo.replace(/\s+/g, '_').toUpperCase(),
    price_ars:  item.json.vcp,
    price_usd:  null,
    asset_type: 'fci',
    source:     'cafci',
    updated_at: new Date().toISOString()
  }
}));

const data = $input.first().json;
const MAP = {
  'bitcoin':     'BTC',
  'ethereum':    'ETH',
  'tether':      'USDT',
  'usd-coin':    'USDC',
  'binancecoin': 'BNB'
};
return Object.entries(data).map(([id, prices]) => ({
  json: {
    ticker:     MAP[id] || id.toUpperCase(),
    price_ars:  prices.ars,
    price_usd:  prices.usd,
    asset_type: 'cripto',
    source:     'coingecko',
    updated_at: new Date().toISOString()
  }
}));

const items = $input.all();
const dolares = {};
for (const item of items) {
  const d = item.json;
  if (d.casa === 'bolsa')           dolares.mep      = d.venta;
  if (d.casa === 'contadoconliqui') dolares.ccl      = d.venta;
  if (d.casa === 'oficial')         dolares.oficial  = d.venta;
  if (d.casa === 'blue')            dolares.blue     = d.venta;
}
return [{
  json: {
    date:       new Date().toISOString().split('T')[0],
    mep:        dolares.mep     || null,
    ccl:        dolares.ccl     || null,
    oficial:    dolares.oficial || null,
    blue:       dolares.blue    || null,
    updated_at: new Date().toISOString()
  }
}];
